class Solution:
    def minFallingPathSum(self, matrix):
        n = len(matrix)
        from functools import lru_cache
        @lru_cache(maxsize=None)
        def dp(r, c):
            if r == n - 1:
                return matrix[r][c]
            best = None
            for nc in (c - 1, c, c + 1):
                if 0 <= nc < n:
                    val = dp(r + 1, nc)
                    if best is None or val < best:
                        best = val
            return matrix[r][c] + best
        result = min(dp(0, c) for c in range(n))
        dp.cache_clear()
        return result

