class Solution:
    def minFallingPathSum(self, matrix):
        n = len(matrix)
        prev = matrix[0][:]
        for r in range(1, n):
            cur = [0] * n
            for c in range(n):
                best = prev[c]
                if c > 0 and prev[c - 1] < best:
                    best = prev[c - 1]
                if c < n - 1 and prev[c + 1] < best:
                    best = prev[c + 1]
                cur[c] = matrix[r][c] + best
            prev = cur
        return min(prev)

